#!/usr/bin/env bash
# high-decay.sh — 搭数据飞轮（「生产 → 数据飞轮」，high decay） SOP walkthrough for AI 产品经理 (LLM 应用 / 生成式 AI / Agent 产品 / Copilot 嵌入 — 跨模型评估 / 工作流设计 / 产品-工程协同).
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="AI 产品经理 (LLM 应用 / 生成式 AI / Agent 产品 / Copilot 嵌入 — 跨模型评估 / 工作流设计 / 产品-工程协同)"
WORKFLOW="搭数据飞轮（「生产 → 数据飞轮」，high decay）"

usage() {
  cat <<EOF
high-decay.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./high-decay.sh             # interactive
  ./high-decay.sh --dry-run
  ./high-decay.sh --json
  ./high-decay.sh --explain
  ./high-decay.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "搭数据飞轮（「生产 → 数据飞轮」，high decay）" 工作流。

一句话: MVP 上线、有真实流量之后，把「用户用得多」变成「产品越用越好」的自增强闭环 —— 从「有流量但没有差异化沉淀」状态到「production trace → 标注 → eval/finetune 数据 → 模型/产品升级 → 更好体验」转起来的飞轮。

入门 SOP 共 5 步, 失败模式自检 4 项。

相关心智模型:
  • Eval 是地基,不是可选项（别 vibe-check）: 「AI 产品的『好』不是看几个 case 觉得行就 ship —— 是先针对你**自己产品的失败模式**建一套可重复、可回归的系统化测量;没有 eval 就是在瞎改。」
  • 先 error analysis,再加功能（PM 亲自看 trace）: 「质量上不去时,资深 AI PM 的第一反应**不是加功能**,是 PM 亲自拉 10-50 个真实 trace（trace 条数量级见 Hamel field-guide T03-S001 / ev

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**设计反馈采集**：在产品里埋用户反馈机制（显式打分 / 隐式信号 / 编辑行为），从 day 1 就想好收什么。PM 主导。跳过 → 上线半年才发现没存到能用的信号，飞轮根本没燃料。 (evidence: [T03-S004])"
  "**系统化 log production trace**：把每次 query 的输入 / 输出 / 工具调用 / 结果完整 log。PM 定字段 + 工程师建管线。跳过 → 出了问题没法复盘，trace 当普通 log 扔了。 (evidence: [T03-S003])"
  "**按计划采样 + 路由给专家**：定期采样 production 日志，把模糊 / 高成本 / 失败 case 自动路由给领域专家标注。PM 定采样策略 + 工程师建路由。跳过 → 攒了一堆数据没人看，等于没攒。 (evidence: [T03-S003, T03-S012])"
  "**专家判断回流进 eval + finetune 数据集**：专家标注既喂 eval 套件（接 Workflow 4），也攒成 finetune 数据集。PM + 领域专家。跳过 → 标注成本花了但只用一次，不沉淀成可复用资产。 (evidence: [T03-S003, T03-S004])"
  "**用沉淀数据更新产品**：优先 prompt / context / 检索更新，够格了才 finetune;evals 和 finetune 数据是少数能跨模型/技术迁移的资产。PM 主导决策 + 工程师执行。跳过 → 飞轮转了但产品没真的变好，闭环断在最后一环。 (evidence: [T03-S003, T03-S004])"
)
declare -a FAILURE_MODES=(
  "**「收集了用户数据」就以为有飞轮**：触发原因 = 把「攒数据」等同于「飞轮」;怎么避免 = 检查是否真闭环回了模型/产品改进。（**CLI 自检项**：Does your \"flywheel\" actually close the loop back into model/product improvement, or are you just accumulating data nobody acts on?） (evidence: 06-glossary data flywheel)"
  "**没从 day 1 设计反馈采集**：触发原因 = 上线时只想着功能;怎么避免 = scoping/MVP 阶段就定好收什么信号。（**CLI 自检项**：Did you design feedback capture before launch? Retrofitting it after months means you've lost the flywheel's fuel.） (evidence: [T03-S004])"
  "**标注数据只用一次、不沉淀**：触发原因 = 没意识到 eval/finetune 数据是可迁移资产;怎么避免 = 专家标注同时喂 eval 套件 + finetune 数据集。（**CLI 自检项**：Are your expert annotations feeding both your eval suite AND a reusable finetune dataset? These are among the few assets that transfer across models.） (evidence: [T03-S003, T03-S004])"
  "**把飞轮当万能护城河、不做 ROI 评估**：触发原因 = 融资叙事诱惑;怎么避免 = 诚实评估飞轮是否真产生可迁移差异化，接受「多数飞轮没转起来」。（**CLI 自检项**：Are you claiming \"data flywheel\" as a moat in pitches? Honestly assess whether it produces transferable differentiation — most flywheels never spin up.） (evidence: 06-glossary data flywheel disputed)"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "high-decay-walkthrough"
fi
